def compute_score() -> tuple[str, float]:
    # Check for extraneous added/removed/modified shapes on slide 2 using ppt_diff
    # For simplicity, use ppt_diff.modified_slides, added_slides, removed_slides
    extraneous_changes = 0
    # Check for added slides -- shouldn't be any for slide 2
    if any(slide.slide_number == 2 for slide in ppt_diff.added_slides):
        extraneous_changes += 1
    # Check for removed slides
    if any(slide.slide_number == 2 for slide in ppt_diff.removed_slides):
        extraneous_changes += 1
    # Check for modified slides
    for old, new in ppt_diff.modified_slides:
        if new.slide_number == 2:
            # If more than one shape added (aside from the required text box), penalize
            if new.element_count > old.element_count + 1:
                extraneous_changes += 1
    if extraneous_changes > 0:
        return ("Extraneous modifications made to slide 2.", 0.0)
    else:
        return ("No extraneous modifications to slide 2.", 1.0)
